package entity;

import java.awt.Graphics2D;
import java.awt.Rectangle;
import java.awt.image.BufferedImage;
import javax.imageio.ImageIO;
import main.GamePanel;
import main.UtilityTool;
import java.io.IOException;
import java.io.InputStream;



public class Entity {
    GamePanel gp;
    public double worldX, worldY;
    public int speed;
    public BufferedImage up1, up2, down1, down2, left1, left2, right1, right2, rightUp1, leftUp1, rightDown1, leftDown1, rightUp2, leftUp2, rightDown2, leftDown2, leftIdle1, leftIdle2, rightIdle1, rightIdle2, downIdle1, downIdle2, upIdle1, upIdle2;
    public String direction;
    public String idleDirection;
    public int spriteCounter = 0;
    public int idleSpriteCounter = 0;
    public int spriteNum = 1;
    public Rectangle solidArea = new Rectangle(0, 0, 48, 48);
    public int solidAreaDefaultX, solidAreaDefaultY;
    public boolean collisionOn = false;
    public int actionLockCounter = 0;
    public boolean onPath = false;
    public boolean idle = false;
    public int idleCounter = 0;
    public int maxIdleTime = 60;

    public Entity(GamePanel gp) {
        this.gp = gp;
    }

    public BufferedImage setup(String imagePath) {
        UtilityTool uTool = new UtilityTool();
        BufferedImage image = null;

        String path = imagePath;
        if (!path.startsWith("/")) path = "/" + path;
        if (!path.toLowerCase().endsWith(".png")) path = path + ".png";

        InputStream is = getClass().getResourceAsStream(path);
        if (is == null) {
            System.err.println("ERROR: resource not found: " + path);
            return null;
        }

        try {
            image = ImageIO.read(is);
            if (image == null) {
                System.err.println("ERROR: ImageIO.read returned null for: " + path);
                return null;
            }
            image = uTool.scaleImage(image, gp.tileSize, gp.tileSize);
        } catch (IOException e) {
            System.err.println("ERROR loading image: " + path);
            e.printStackTrace();
            return null;
        } finally {
            try {
                is.close();
            } catch (IOException ignored) {
            }
        }

        return image;
    }

    public void setAction() {
    }

    public void update() {
        setAction();

        if(idle) {
            collisionOn = false;

            spriteCounter++;
            if(spriteCounter > 12) {
                spriteNum = spriteNum == 1 ? 2 : 1;
                spriteCounter = 0;
            } else {
                idleSpriteCounter++;
                if(idleSpriteCounter > 32) {
                    spriteNum = spriteNum == 1 ? 2 : 1;
                    idleSpriteCounter = 0;
                }
            }

            idleCounter++;
            if(idleCounter >= maxIdleTime) {
                idle = false;
                idleCounter = 0;
            }

            return;
        }


        idleCounter++;
            if(idleCounter >= maxIdleTime) {
                idle = false;
                idleCounter = 0;
                if(idleDirection != null && idleDirection.startsWith("idle_")) {
                    String dir = idleDirection.substring(5);
                    direction = dir;
                } else {
                    if(direction == null) direction = "down";
                }
            }

            return;
        }

        collisionOn = false;
        gp.cChecker.checkTile(this);

        if(!collisionOn) {
            switch(direction) {
                case "up": worldY -= speed; break;
                case "down": worldY += speed; break;
                case "left": worldX -= speed; break;
                case "right": worldX += speed; break;
            }

            spriteCounter++;
            if(spriteCounter > 12) {
                spriteNum = spriteNum == 1 ? 2 : 1;
                spriteCounter = 0;
            }
        } else {
            idle = true;
            idleCounter = 0;
            if(direction == null) direction = "down";
            if("up".equals(direction)) idleDirection = "idle_up";
            else if("down".equals(direction)) idleDirection = "idle_down";
            else if("left".equals(direction)) idleDirection = "idle_left";
            else idleDirection = "idle_right";
            direction = idleDirection;

            idleSpriteCounter++;
            if(idleSpriteCounter > 32) {
                spriteNum = spriteNum == 1 ? 2 : 1;
                idleSpriteCounter = 0;
            }
        }
    }

    public void draw(Graphics2D g2) {
        BufferedImage image = null;
        int screenX = (int) (worldX - gp.player.worldX + gp.player.screenX);
        int screenY = (int) (worldY - gp.player.worldY + gp.player.screenY);
        if (worldX + gp.tileSize > gp.player.worldX - gp.player.screenX &&
                worldX - gp.tileSize < gp.player.worldX + gp.player.screenX &&
                worldY + gp.tileSize > gp.player.worldY - gp.player.screenY &&
                worldY - gp.tileSize < gp.player.worldY + gp.player.screenY) {
            String dir = (direction != null) ? direction : (idleDirection != null ? idleDirection : "down");
            switch (dir) {
                // MOVIMENTO
                case "up":
                    if (spriteNum == 1) image = up1;
                    else image = up2;
                    break;
                case "down":
                    if (spriteNum == 1) image = down1;
                    else image = down2;
                    break;
                case "left":
                    if (spriteNum == 1) image = left1;
                    else image = left2;
                    break;
                case "right":
                    if (spriteNum == 1) image = right1;
                    else image = right2;
                    break;
                // IDLE DIREZIONALE
                case "idle_up":
                    if (spriteNum == 1) image = upIdle1;
                    else image = upIdle2;
                    break;
                case "idle_down":
                    if (spriteNum == 1) image = downIdle1;
                    else image = downIdle2;
                    break;
                case "idle_left":
                    if (spriteNum == 1) image = leftIdle1;
                    else image = leftIdle2;
                    break;
                case "idle_right":
                    if (spriteNum == 1) image = rightIdle1;
                    else image = rightIdle2;
                    break;
                // FALLBACK
                default:
                    if (spriteNum == 1) image = downIdle1;
                    else image = downIdle2;
                    break;
            }
        }
        g2.drawImage(image, screenX, screenY, null);
    }
}

